<?php
require_once __DIR__.'/app/layout.php'; require_admin();$row=settings();$error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$sig=upload_signature('boss_signature',$row['boss_signature_path']);$st=db()->prepare('UPDATE settings SET office_city=?,boss_name=?,boss_nip=?,boss_position=?,boss_signature_path=?,max_absences=? WHERE id=1');$st->execute([trim($_POST['office_city']),trim($_POST['boss_name']),trim($_POST['boss_nip']),trim($_POST['boss_position']),$sig,max(1,(int)$_POST['max_absences'])]);log_activity('save','settings',1);flash('success','Pengaturan berhasil disimpan.');redirect('settings.php');}catch(Throwable $e){$error=$e->getMessage();}}
page_header('Pengaturan','settings');if($error)echo '<div class="alert error">'.e($error).'</div>';?><div class="card"><form method="post" enctype="multipart/form-data"><?=csrf_input()?><div class="form-grid"><div class="field"><label>Kota surat</label><input name="office_city" value="<?=e($row['office_city'])?>" required></div><div class="field"><label>Maksimal lupa absen per bulan</label><input type="number" min="1" name="max_absences" value="<?=e((string)$row['max_absences'])?>" required></div><div class="field full"><label>Nama Kepala Subdirektorat</label><input name="boss_name" value="<?=e($row['boss_name'])?>" required></div><div class="field"><label>NIP Kepala Subdirektorat</label><input name="boss_nip" value="<?=e($row['boss_nip'])?>" required></div><div class="field"><label>Jabatan</label><input name="boss_position" value="<?=e($row['boss_position'])?>" required></div><div class="field full"><label>Upload tanda tangan Kepala Subdirektorat (PNG/JPG)</label><input type="file" name="boss_signature" accept="image/png,image/jpeg"><div class="help">Tanda tangan ini hanya akan muncul pada surat yang berstatus <b>Disetujui</b>. Untuk status Menunggu atau Tidak Disetujui, tanda tangan atasan tidak ditampilkan.</div><?php if($row['boss_signature_path']):?><img class="signature-preview" src="<?=e($row['boss_signature_path'])?>"><?php endif;?></div></div><div class="form-actions"><button class="btn">Simpan Pengaturan</button></div></form></div><?php page_footer();
